from django.db import models
from django.contrib.auth.hashers import make_password, check_password

class User(models.Model):
    email = models.EmailField(unique=True)
    nombre = models.CharField(max_length=120, blank=True)
    telefono = models.CharField(max_length=20, blank=True)
    es_administrador = models.BooleanField(default=False)
    password = models.CharField(max_length=255)
    created_at = models.DateTimeField(auto_now_add=True)
    updated_at = models.DateTimeField(auto_now=True)

    def set_password(self, raw_password):
        self.password = make_password(raw_password)

    def check_password(self, raw_password):
        return check_password(raw_password, self.password)

    def __str__(self):
        return self.email

    class Meta:
        ordering = ['-created_at']

from django import forms
from django.core.exceptions import ValidationError
from .models import User

class RegisterForm(forms.ModelForm):
    password = forms.CharField(
        widget=forms.PasswordInput,
        label='Contraseña',
        min_length=6
    )
    password_confirm = forms.CharField(
        widget=forms.PasswordInput,
        label='Confirmar contraseña',
        min_length=6
    )

    class Meta:
        model = User
        fields = ['email', 'nombre', 'telefono']
        labels = {
            'email': 'Correo electrónico',
            'nombre': 'Nombre',
            'telefono': 'Teléfono',
        }

    def clean_email(self):
        email = self.cleaned_data.get('email')
        if User.objects.filter(email=email).exists():
            raise ValidationError('Este correo electrónico ya está registrado.')
        return email

    def clean(self):
        cleaned_data = super().clean()
        password = cleaned_data.get('password')
        password_confirm = cleaned_data.get('password_confirm')
        if password and password_confirm and password != password_confirm:
            raise ValidationError('Las contraseñas no coinciden.')
        return cleaned_data

    def save(self, commit=True):
        user = super().save(commit=False)
        user.set_password(self.cleaned_data['password'])
        if commit:
            user.save()
        return user

class LoginForm(forms.Form):
    email = forms.EmailField(label='Correo electrónico')
    password = forms.CharField(
        widget=forms.PasswordInput,
        label='Contraseña'
    )

from django.shortcuts import render, redirect
from django.views import View
from django.contrib import messages
from django.contrib.auth.decorators import login_required
from django.utils.decorators import method_decorator
from .models import User
from .forms import RegisterForm, LoginForm
from reservations.models import Reserva

class RegisterView(View):
    def get(self, request):
        form = RegisterForm()
        return render(request, 'accounts/register.html', {'form': form})

    def post(self, request):
        form = RegisterForm(request.POST)
        if form.is_valid():
            user = form.save()
            request.session['user_id'] = user.id
            messages.success(request, 'Registro exitoso. Bienvenido.')
            return redirect('core:home')
        return render(request, 'accounts/register.html', {'form': form})

class LoginView(View):
    def get(self, request):
        form = LoginForm()
        return render(request, 'accounts/login.html', {'form': form})

    def post(self, request):
        form = LoginForm(request.POST)
        if form.is_valid():
            email = form.cleaned_data['email']
            password = form.cleaned_data['password']
            try:
                user = User.objects.get(email=email)
                if user.check_password(password):
                    request.session['user_id'] = user.id
                    messages.success(request, 'Inicio de sesión exitoso.')
                    return redirect('core:home')
                else:
                    messages.error(request, 'Correo o contraseña incorrectos.')
            except User.DoesNotExist:
                messages.error(request, 'Correo o contraseña incorrectos.')
        return render(request, 'accounts/login.html', {'form': form})

class LogoutView(View):
    def post(self, request):
        if 'user_id' in request.session:
            del request.session['user_id']
        messages.success(request, 'Sesión cerrada correctamente.')
        return redirect('core:home')

@method_decorator(login_required(login_url='accounts:login'), name='dispatch')
class ProfileView(View):
    def get(self, request):
        user_id = request.session.get('user_id')
        if not user_id:
            return redirect('accounts:login')
        try:
            user = User.objects.get(id=user_id)
            reservas = Reserva.objects.filter(cliente_id=user_id).order_by('-created_at')
            return render(request, 'accounts/profile.html', {
                'user': user,
                'reservas': reservas
            })
        except User.DoesNotExist:
            return redirect('accounts:login')

from django.db import models

class Categoria(models.Model):
    nombre = models.CharField(max_length=120, unique=True)
    descripcion = models.TextField(blank=True)

    def __str__(self):
        return self.nombre

    class Meta:
        ordering = ['nombre']

class Puerto(models.Model):
    nombre = models.CharField(max_length=120, unique=True)
    ubicacion = models.CharField(max_length=255, blank=True)

    def __str__(self):
        return self.nombre

    class Meta:
        ordering = ['nombre']

class Fabricante(models.Model):
    nombre = models.CharField(max_length=120, unique=True)
    pais = models.CharField(max_length=120, blank=True)

    def __str__(self):
        return self.nombre

    class Meta:
        ordering = ['nombre']

class Barco(models.Model):
    nombre = models.CharField(max_length=120)
    categoria = models.ForeignKey(Categoria, on_delete=models.PROTECT)
    puerto = models.ForeignKey(Puerto, on_delete=models.PROTECT)
    fabricante = models.ForeignKey(Fabricante, on_delete=models.PROTECT)
    precio_dia = models.DecimalField(max_digits=8, decimal_places=2)
    capacidad = models.PositiveIntegerField()
    imagen = models.ImageField(upload_to='barcos/', blank=True, null=True)
    descripcion = models.TextField(blank=True)
    disponible = models.BooleanField(default=True)
    cantidad_disponible = models.PositiveIntegerField(default=1)
    created_at = models.DateTimeField(auto_now_add=True)
    updated_at = models.DateTimeField(auto_now=True)

    def __str__(self):
        return self.nombre

    class Meta:
        ordering = ['-created_at']

