from django.views import View
from django.db.models import Q
from .models import Barco, Categoria, Puerto, Fabricante

class BarcoListView(View):
    def get(self, request):
        barcos = Barco.objects.all()
        categorias = Categoria.objects.all()
        puertos = Puerto.objects.all()
        fabricantes = Fabricante.objects.all()

        # Búsqueda por nombre
        search = request.GET.get('search', '')
        if search:
            barcos = barcos.filter(Q(nombre__icontains=search))

        # Filtros
        categoria_id = request.GET.get('categoria')
        if categoria_id:
            barcos = barcos.filter(categoria_id=categoria_id)

        puerto_id = request.GET.get('puerto')
        if puerto_id:
            barcos = barcos.filter(puerto_id=puerto_id)

        fabricante_id = request.GET.get('fabricante')
        if fabricante_id:
            barcos = barcos.filter(fabricante_id=fabricante_id)

        precio_min = request.GET.get('precio_min')
        if precio_min:
            try:
                barcos = barcos.filter(precio_dia__gte=float(precio_min))
            except ValueError:
                pass

        precio_max = request.GET.get('precio_max')
        if precio_max:
            try:
                barcos = barcos.filter(precio_dia__lte=float(precio_max))
            except ValueError:
                pass

        capacidad_min = request.GET.get('capacidad_min')
        if capacidad_min:
            try:
                barcos = barcos.filter(capacidad__gte=int(capacidad_min))
            except ValueError:
                pass

        # Agrupar por categoría
        barcos_por_categoria = {}
        for barco in barcos:
            if barco.categoria.nombre not in barcos_por_categoria:
                barcos_por_categoria[barco.categoria.nombre] = []
            barcos_por_categoria[barco.categoria.nombre].append(barco)

        context = {
            'barcos': barcos,
            'barcos_por_categoria': barcos_por_categoria,
            'categorias': categorias,
            'puertos': puertos,
            'fabricantes': fabricantes,
            'search': search,
        }
        return render(request, 'catalog/list.html', context)

class BarcoDetailView(View):
    def get(self, request, id):
        barco = get_object_or_404(Barco, id=id)
        return render(request, 'catalog/detail.html', {'barco': barco})

def get_cart(request):
    if 'cart' not in request.session:
        request.session['cart'] = {}
    return request.session['cart']

def add_to_cart(request, barco_id, cantidad):
    cart = get_cart(request)
    barco_id_str = str(barco_id)
    if barco_id_str in cart:
        cart[barco_id_str]['cantidad'] += cantidad
    else:
        cart[barco_id_str] = {'cantidad': cantidad}
    request.session.modified = True

def update_cart(request, barco_id, cantidad):
    cart = get_cart(request)
    barco_id_str = str(barco_id)
    if cantidad <= 0:
        if barco_id_str in cart:
            del cart[barco_id_str]
    else:
        if barco_id_str in cart:
            cart[barco_id_str]['cantidad'] = cantidad
    request.session.modified = True

def clear_cart(request):
    request.session['cart'] = {}
    request.session.modified = True

def get_cart_items(request):
    from catalog.models import Barco
    cart = get_cart(request)
    items = []
    for barco_id_str, item in cart.items():
        try:
            barco = Barco.objects.get(id=int(barco_id_str))
            items.append({
                'barco': barco,
                'cantidad': item['cantidad'],
                'subtotal': barco.precio_dia * item['cantidad']
            })
        except Barco.DoesNotExist:
            pass
    return items

def get_cart_total(request):
    items = get_cart_items(request)
    return sum(item['subtotal'] for item in items)

from django.shortcuts import render, redirect
from django.views import View
from django.http import JsonResponse
from django.contrib import messages
from catalog.models import Barco
from .services import get_cart, add_to_cart, update_cart, clear_cart, get_cart_items, get_cart_total

class CartView(View):
    def get(self, request):
        items = get_cart_items(request)
        total = get_cart_total(request)
        return render(request, 'cart/view.html', {
            'items': items,
            'total': total
        })

class AddToCartView(View):
    def post(self, request):
        barco_id = request.POST.get('barco_id')
        cantidad = request.POST.get('cantidad', 1)
        try:
            barco_id = int(barco_id)
            cantidad = int(cantidad)
            if cantidad <= 0:
                messages.error(request, 'La cantidad debe ser mayor a 0.')
                return redirect('catalog:barco_detail', id=barco_id)
            barco = Barco.objects.get(id=barco_id)
            if cantidad > barco.cantidad_disponible:
                messages.error(request, f'Solo hay {barco.cantidad_disponible} unidades disponibles.')
                return redirect('catalog:barco_detail', id=barco_id)
            add_to_cart(request, barco_id, cantidad)
            messages.success(request, f'{barco.nombre} añadido a la cesta.')
        except (ValueError, Barco.DoesNotExist):
            messages.error(request, 'Error al añadir a la cesta.')
        return redirect('catalog:barco_list')

class UpdateCartView(View):
    def post(self, request):
        barco_id = request.POST.get('barco_id')
        cantidad = request.POST.get('cantidad', 0)
        try:
            barco_id = int(barco_id)
            cantidad = int(cantidad)
            update_cart(request, barco_id, cantidad)
            messages.success(request, 'Cesta actualizada.')
        except ValueError:
            messages.error(request, 'Error al actualizar la cesta.')
        return redirect('cart:view')

class ClearCartView(View):
    def post(self, request):
        clear_cart(request)
        messages.success(request, 'Cesta vaciada.')
        return redirect('cart:view')

