        <h3>Filtros</h3>
        <form method="get" style="display: flex; flex-direction: column; gap: 15px;">
            <div>
                <label for="search">Buscar por nombre:</label>
                <input type="text" id="search" name="search" value="{{ search }}" placeholder="Nombre del barco">
            </div>
            <div>
                <label for="categoria">Categoría:</label>
                <select id="categoria" name="categoria">
                    <option value="">Todas</option>
                    {% for cat in categorias %}
                        <option value="{{ cat.id }}" {% if request.GET.categoria|stringformat:"s" == cat.id|stringformat:"s" %}selected{% endif %}>{{ cat.nombre }}</option>
                    {% endfor %}
                </select>
            </div>
            <div>
                <label for="puerto">Puerto:</label>
                <select id="puerto" name="puerto">
                    <option value="">Todos</option>
                    {% for puerto in puertos %}
                        <option value="{{ puerto.id }}" {% if request.GET.puerto|stringformat:"s" == puerto.id|stringformat:"s" %}selected{% endif %}>{{ puerto.nombre }}</option>
                    {% endfor %}
                </select>
            </div>
            <div>
                <label for="fabricante">Fabricante:</label>
                <select id="fabricante" name="fabricante">
                    <option value="">Todos</option>
                    {% for fab in fabricantes %}
                        <option value="{{ fab.id }}" {% if request.GET.fabricante|stringformat:"s" == fab.id|stringformat:"s" %}selected{% endif %}>{{ fab.nombre }}</option>
                    {% endfor %}
                </select>
            </div>
            <div>
                <label for="precio_min">Precio mínimo:</label>
                <input type="number" id="precio_min" name="precio_min" value="{{ request.GET.precio_min }}" placeholder="0">
            </div>
            <div>
                <label for="precio_max">Precio máximo:</label>
                <input type="number" id="precio_max" name="precio_max" value="{{ request.GET.precio_max }}" placeholder="1000">
            </div>
            <div>
                <label for="capacidad_min">Capacidad mínima:</label>
                <input type="number" id="capacidad_min" name="capacidad_min" value="{{ request.GET.capacidad_min }}" placeholder="1">
            </div>
            <button type="submit" class="btn" style="width: 100%;">Aplicar Filtros</button>
            <a href="{% url 'catalog:barco_list' %}" class="btn btn-secondary" style="width: 100%; text-align: center;">Limpiar Filtros</a>
        </form>
    </div>

    <div>
        {% if barcos %}
            {% for categoria_nombre, barcos_cat in barcos_por_categoria.items %}
                <h3>{{ categoria_nombre }}</h3>
                <div style="display: grid; grid-template-columns: repeat(auto-fill, minmax(250px, 1fr)); gap: 20px; margin-bottom: 30px;">
